<script>
export default {
  name: "ToggleMenuComponent",

  data() {
    return {
      menuNames: ["Home", "Profile", "Settings"],
      toggledMenus: []
    };
  },

  methods: {
    toggleMenu(menuName) {
      const index = this.toggledMenus.indexOf(menuName);
      if (index > -1) {
        this.toggledMenus.splice(index, 1);
      } else {
        this.toggledMenus.push(menuName);
      }
    }
  }
};
</script>

